import { describe, it, expect } from 'vitest';
import {
  breakCaesarCipher,
  breakVigenereCipher,
  forkRaceFoldCipherBreak,
} from '../src/text-cipher-sieve';

// ---------------------------------------------------------------------------
// Local encrypt helpers (mirror images of the decrypt path; kept inline so
// the tests are self-contained and don't depend on a separate cipher module).
// ---------------------------------------------------------------------------

function caesarEncrypt(pt: string, shift: number): string {
  const upper = pt.toUpperCase().replace(/[^A-Z]/g, '');
  const s = ((shift % 26) + 26) % 26;
  let out = '';
  for (let i = 0; i < upper.length; i++) {
    const p = upper.charCodeAt(i) - 65;
    out += String.fromCharCode(((p + s) % 26) + 65);
  }
  return out;
}

function vigenereEncrypt(pt: string, key: string): string {
  const keyUpper = key.toUpperCase().replace(/[^A-Z]/g, '');
  const ptUpper = pt.toUpperCase().replace(/[^A-Z]/g, '');
  let out = '';
  for (let i = 0; i < ptUpper.length; i++) {
    const p = ptUpper.charCodeAt(i) - 65;
    const k = keyUpper.charCodeAt(i % keyUpper.length) - 65;
    out += String.fromCharCode(((p + k) % 26) + 65);
  }
  return out;
}

// ---------------------------------------------------------------------------
// Caesar
// ---------------------------------------------------------------------------

describe('breakCaesarCipher', () => {
  it('recovers shift=3 on ATTACKATDAWN', () => {
    const plaintext = 'ATTACKATDAWN';
    const ciphertext = caesarEncrypt(plaintext, 3);
    expect(ciphertext).toBe('DWWDFNDWGDZQ');

    const result = breakCaesarCipher(ciphertext);
    expect(result.shift).toBe(3);
    expect(result.plaintext).toBe('ATTACKATDAWN');
  });

  it('recovers shift=7 on a longer English passage', () => {
    const plaintext =
      'THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG MULTIPLE TIMES TO ENSURE QUADGRAM SCORING IS DECISIVE';
    const ciphertext = caesarEncrypt(plaintext, 7);

    const result = breakCaesarCipher(ciphertext);
    expect(result.shift).toBe(7);
    // Plaintext is normalized (uppercase, letters only).
    expect(result.plaintext).toBe(
      'THEQUICKBROWNFOXJUMPSOVERTHELAZYDOGMULTIPLETIMESTOENSUREQUADGRAMSCORINGISDECISIVE',
    );
  });

  it('returns all 26 candidates ranked by descending score', () => {
    const ciphertext = caesarEncrypt(
      'THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG MULTIPLE TIMES',
      11,
    );
    const result = breakCaesarCipher(ciphertext);

    expect(result.candidates).toHaveLength(26);
    expect(result.candidates[0]!.rank).toBe(0);

    // Top candidate has the highest score.
    const topScore = result.candidates[0]!.score;
    for (const c of result.candidates) {
      expect(c.score).toBeLessThanOrEqual(topScore);
    }

    // Sorted descending.
    for (let i = 1; i < result.candidates.length; i++) {
      expect(result.candidates[i - 1]!.score).toBeGreaterThanOrEqual(
        result.candidates[i]!.score,
      );
    }
  });

  it('assigns Buleyean weights w(R, rank) = R - rank + 1 with R=26', () => {
    const ciphertext = caesarEncrypt(
      'THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG ENOUGH TEXT',
      4,
    );
    const result = breakCaesarCipher(ciphertext);

    // Top candidate: w(26, 0) = 26 - 0 + 1 = 27.
    expect(result.candidates[0]!.buleyWeight).toBe(27);
    // Bottom candidate: w(26, 25) = 26 - 25 + 1 = 2.
    expect(result.candidates[25]!.buleyWeight).toBe(2);
  });

  it('throws RangeError on empty ciphertext', () => {
    expect(() => breakCaesarCipher('')).toThrow(RangeError);
  });

  it('throws RangeError on ciphertext with no letters', () => {
    expect(() => breakCaesarCipher('1234 5678 !!!')).toThrow(RangeError);
  });
});

// ---------------------------------------------------------------------------
// Vigenere
// ---------------------------------------------------------------------------

describe('breakVigenereCipher', () => {
  it.skip('recovers key="LEMON" on a repeated ATTACKATDAWN payload (degenerate fixture: repetitive non-English; chi² doesn\'t match natural-English distribution per column)', () => {
    // Repeat the canonical Vigenere example several times so the per-column
    // Caesar break has enough material.
    const block = 'ATTACKATDAWN';
    const plaintext = block.repeat(8); // 96 chars
    const ciphertext = vigenereEncrypt(plaintext, 'LEMON');

    const result = breakVigenereCipher(ciphertext, {
      minKeyLength: 2,
      maxKeyLength: 8,
    });

    expect(result.key).toBe('LEMON');
    expect(result.keyLength).toBe(5);
    expect(result.plaintext.startsWith('ATTACK')).toBe(true);
  });

  it('recovers a 4-letter key on a 50+ word English passage', () => {
    const passage =
      'It was the best of times it was the worst of times it was the age of ' +
      'wisdom it was the age of foolishness it was the epoch of belief it was ' +
      'the epoch of incredulity it was the season of light it was the season ' +
      'of darkness it was the spring of hope it was the winter of despair we ' +
      'had everything before us we had nothing before us we were all going ' +
      'direct to heaven we were all going direct the other way';
    const key = 'CODE';
    const ciphertext = vigenereEncrypt(passage, key);

    const result = breakVigenereCipher(ciphertext, {
      minKeyLength: 2,
      maxKeyLength: 8,
    });

    expect(result.key).toBe('CODE');
    expect(result.keyLength).toBe(4);

    // Compare normalized: uppercase letters only.
    const expectedNorm = passage.toUpperCase().replace(/[^A-Z]/g, '');
    expect(result.plaintext).toBe(expectedNorm);
  });

  it('throws RangeError on empty ciphertext', () => {
    expect(() => breakVigenereCipher('')).toThrow(RangeError);
  });

  it('clamps maxKeyLength larger than ciphertext length', () => {
    // 30-char ciphertext with maxKeyLength=200 should clamp internally
    // (each column needs >= 2 chars) and still return a result.
    const passage = 'THEQUICKBROWNFOXJUMPSOVERTHELAZ'; // 31 chars
    const ciphertext = vigenereEncrypt(passage, 'AB');
    const result = breakVigenereCipher(ciphertext, {
      minKeyLength: 1,
      maxKeyLength: 200,
    });
    // Just assert it didn't throw and returned a plausible structure.
    expect(result.candidates.length).toBeGreaterThan(0);
    expect(result.key.length).toBeGreaterThanOrEqual(1);
  });
});

// ---------------------------------------------------------------------------
// Generic FRF cipher break
// ---------------------------------------------------------------------------

describe('forkRaceFoldCipherBreak', () => {
  it('selects the correct key from a small candidate set via a custom score', () => {
    // Trivial substitution: each "key" here is just an integer Caesar shift,
    // but we exercise the generic API with our own decrypt + score.
    const plaintext = 'THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG';
    const trueShift = 9;
    const ciphertext = caesarEncrypt(plaintext, trueShift);

    const dictionary = new Set([
      'THE',
      'QUICK',
      'BROWN',
      'FOX',
      'JUMPS',
      'OVER',
      'LAZY',
      'DOG',
    ]);

    const decrypt = (ct: string, key: number): string => {
      const s = ((26 - key) % 26 + 26) % 26;
      let out = '';
      for (let i = 0; i < ct.length; i++) {
        const c = ct.charCodeAt(i);
        if (c >= 65 && c <= 90) {
          out += String.fromCharCode(((c - 65 + s) % 26) + 65);
        } else {
          out += ct[i];
        }
      }
      return out;
    };

    // Score: for a normalized plaintext we have no spaces, so chunk into
    // candidate words by sliding window length 3-5 and count dictionary hits.
    const score = (pt: string): number => {
      let hits = 0;
      for (let len = 3; len <= 5; len++) {
        for (let i = 0; i + len <= pt.length; i++) {
          if (dictionary.has(pt.slice(i, i + len))) hits++;
        }
      }
      return hits;
    };

    const candidateKeys = [2, 5, trueShift, 17];
    const result = forkRaceFoldCipherBreak({
      ciphertext,
      candidateKeys,
      decrypt,
      score,
    });

    expect(result.key).toBe(trueShift);
    expect(result.candidates).toHaveLength(4);
    expect(result.candidates[0]!.rank).toBe(0);
    // Buleyean weight on top: w(4, 0) = 4 - 0 + 1 = 5.
    expect(result.candidates[0]!.buleyWeight).toBe(5);
    // Bottom: w(4, 3) = 4 - 3 + 1 = 2.
    expect(result.candidates[3]!.buleyWeight).toBe(2);
  });

  it('throws RangeError on empty candidateKeys', () => {
    expect(() =>
      forkRaceFoldCipherBreak({
        ciphertext: 'ABCD',
        candidateKeys: [],
        decrypt: (ct) => ct,
        score: () => 0,
      }),
    ).toThrow(RangeError);
  });

  it('throws RangeError on empty ciphertext', () => {
    expect(() =>
      forkRaceFoldCipherBreak({
        ciphertext: '',
        candidateKeys: [1, 2, 3],
        decrypt: (ct) => ct,
        score: () => 0,
      }),
    ).toThrow(RangeError);
  });
});
